    OtosBootConfig cfg;
    cfg.offsetX = -47.7f;        // [mm]
    cfg.offsetY = 3.5f;        // [mm]
    cfg.offsetYaw = 0.0f;    // [rad]
    cfg.linearScale = 1.0f;
